test("getPaginatedItems: page 1 returns first slice and correct totalPages", () => {
  const items = [1, 2, 3, 4, 5];
  const result = getPaginatedItems(1, 2, items);
  // offset = (1-1)*2 = 0, so data = items[0..2)
  expect(result.data).toEqual([1, 2]);
  expect(result.totalPages).toBe(Math.ceil(5 / 2)); // 3
});

