test("hasSufficientFunds/getChargeAmount/getTransferAmount: balance exceeds transaction amount", () => {
  const sender = { balance: 5000 } as any;
  const transaction = { amount: 3000 } as any;
  // difference = 5000 - 3000 = 2000 (positive) -> sufficient funds
  expect(hasSufficientFunds(sender, transaction)).toBe(true);
  expect(getChargeAmount(sender, transaction)).toBe(2000);
  expect(getTransferAmount(sender, transaction)).toBe(2000);
});

test("hasSufficientFunds/getChargeAmount: balance less than transaction amount is insufficient", () => {
  const sender = { balance: 1000 } as any;
  const transaction = { amount: 3000 } as any;
  // difference = 1000 - 3000 = -2000 (negative) -> insufficient funds
  expect(hasSufficientFunds(sender, transaction)).toBe(false);
  expect(getChargeAmount(sender, transaction)).toBe(2000); // Math.abs(-2000)
});

